GameAnalytics = {}
GameAnalytics.Enable = false
GameAnalytics.OffsetTs = 0
GameAnalytics.Custom01 = "G1"
GameAnalytics.Custom02 = "Test"
GameAnalytics.RetryTimes = 3

local function getCoinName(coinId)
    coinId = coinId or 0
    if coinId == 1 then
        return "Cube"
    end
    if coinId == 2 then
        return "Gold"
    end
    if coinId == 3 then
        return "Money"
    end
    if coinId == 4 then
        return "GameCustom"
    end
    return "NoDefine"
end

function GameAnalytics:init(enable, serverTs, custom1, custom2)
    self.Enable = enable
    self.OffsetTs = os.time() - tonumber(tostring(serverTs))
    self.Custom01 = custom1
    self.Custom02 = custom2
    GameAnalyticsCache:initClientInfo()
end

function GameAnalytics:isEnable()
    return self.Enable
end

function GameAnalytics:getClientTs()
    return os.time() - self.OffsetTs
end

function GameAnalytics:sendEvents(events)
    if #events == 0 then
        return
    end
    GameAnalyticsRequest.Instance():asyncEvents(json.encode(events), GameAnalytics.RetryTimes)
end

---Resource events are for tracking the flow of virtual currency registering the
---amounts users are spending (sink) and receiving (source) for a specified virtual currency.
---@param action string eventId [event id, eg: BuyGun]
---@param itemId string_or_number itemId [item id, eg: 103]
---@param coinId number itemId [coinId, eg: 1|2|3|4]
---@param amount number amount [currency amount eg: 100]
---eventId structure
---pattern:^Sink:[A-Za-z]{1,64}:[A-Za-z0-9\\s\\-_\\.\\(\\)\\!\\?]{1,64}:[A-Za-z0-9\\s\\-_\\.\\(\\)\\!\\?]{1,64}$
function GameAnalytics:resourceSink(action, itemId, coinId, amount)
    if not GameAnalytics:isEnable() then
        return
    end
    local coin = getCoinName(coinId) .. ":"
    action = (action or "test") .. ":"
    itemId = itemId or "1"
    local eventId = "Sink:" .. coin .. action .. itemId
    GameAnalyticsCache:addEventCache({
        category = "resource",
        event_id = eventId,
        amount = amount
    })
end

